### Prop Drilling

Prop drilling occurs when data passes through multiple intermediate components that do not need the data themselves, only to reach a deeply nested child.

---

### The Problem

```jsx
function App() {
  const [user, setUser] = useState(null);
  return <Layout user={user} setUser={setUser} />;
}

function Layout({ user, setUser }) {
  return <Header user={user} setUser={setUser} />;
}

function Header({ user, setUser }) {
  return <UserMenu user={user} setUser={setUser} />;
}

function UserMenu({ user, setUser }) {
  return <button onClick={() => setUser(null)}>Logout</button>;
}
```

### Solutions Comparison

| Solution | Best For |
|----------|----------|
| Component composition | Simple restructuring |
| Context API | Global data (theme, auth, locale) |
| State management library | Complex app state |
| Children prop / render props | Localized prop passing |

### Solution 1: Component Composition

```jsx
function App() {
  const [user, setUser] = useState(null);
  return (
    <Layout>
      <Header>
        <UserMenu user={user} setUser={setUser} />
      </Header>
    </Layout>
  );
}
```

### Solution 2: Context API

```jsx
const UserContext = createContext(null);

function App() {
  const [user, setUser] = useState(null);
  return (
    <UserContext.Provider value={{ user, setUser }}>
      <Layout />
    </UserContext.Provider>
  );
}

function UserMenu() {
  const { user, setUser } = useContext(UserContext);
  return <button onClick={() => setUser(null)}>Logout</button>;
}
```

> **Key Point:** Before reaching for context, consider if component composition solves the problem. Lifting content up (using children) often eliminates the need for prop drilling without adding complexity.

codeExample:
// Composition approach
function App() {
  const [theme, setTheme] = useState('light');

  return (
    <Page
      header={<Header><ThemeToggle theme={theme} setTheme={setTheme} /></Header>}
      sidebar={<Sidebar />}
      content={<Content />}
    />
  );
}
